@namespace Lumeo
@inject IComponentInteropService Interop

@{
    var context = new NavigationMenuContext(_activeItemId, EventCallback.Factory.Create<string?>(this, SetActiveItemId), this, DelayDuration);
}

@* aria-label names the navigation landmark so AT users can distinguish it from
   other <nav>s on the page (Radix / APG NavigationMenu contract). *@
<nav class="@CssClass" aria-label="@Label" @attributes="AdditionalAttributes">
    <CascadingValue Value="context" IsFixed="false">
        @ChildContent
    </CascadingValue>
</nav>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Accessible name for the &lt;nav&gt; landmark. Defaults to "Main".</summary>
    [Parameter] public string Label { get; set; } = "Main";

    /// <summary>
    /// Controlled value of the currently-open item. Bind with
    /// <c>@bind-Value</c>/<see cref="ValueChanged"/>. The value matches the open
    /// <see cref="NavigationMenuItem.Value"/> (or its auto id when none is set);
    /// <c>null</c> means no submenu is open. Leave unset for uncontrolled use.
    /// </summary>
    [Parameter] public string? Value { get; set; }

    /// <summary>Raised when the open item changes (user hover/click/keyboard, or an
    /// item close). Carries the new open item's value, or <c>null</c> when closed.</summary>
    [Parameter] public EventCallback<string?> ValueChanged { get; set; }

    /// <summary>Initial open item for uncontrolled use (ignored once <see cref="Value"/>
    /// is bound). <c>null</c> (default) opens nothing.</summary>
    [Parameter] public string? DefaultValue { get; set; }

    /// <summary>
    /// Grace window in milliseconds before a hovered submenu closes after the
    /// pointer leaves it. Radix's forgiveness delay: moving between adjacent
    /// triggers, or briefly slipping off the panel, does not immediately dismiss.
    /// Defaults to 150ms.
    /// </summary>
    [Parameter] public int DelayDuration { get; set; } = 150;

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string? _activeItemId;

    // Controlled/uncontrolled disambiguation, mirroring the menu RadioGroups. The
    // open item lives in a private field so an uncontrolled menu's optimistic
    // open/close survives an unrelated parent re-render, and a controlled parent
    // can veto (re-render with the old Value) to roll the state back.
    private bool _seeded;
    private string? _lastValueParam;
    private string? _lastPushed;   // the last value WE emitted via ValueChanged

    protected override void OnParametersSet()
    {
        if (!_seeded)
        {
            // DefaultValue seeds the open item ONLY when uncontrolled. When controlled
            // (ValueChanged bound or a non-null Value supplied), honor Value verbatim —
            // including Value == null meaning "closed" — and ignore DefaultValue (Radix
            // semantics). Previously DefaultValue opened the menu while _lastPushed stayed
            // null, so a later controlled render with Value == null was mistaken for the
            // echo of our own push and the parent could never force the menu closed (P2 r2).
            var controlled = ValueChanged.HasDelegate || Value is not null;
            _activeItemId = controlled ? Value : DefaultValue;
            _lastValueParam = Value;
            _lastPushed = Value;
            _seeded = true;
            return;
        }

        if (ValueChanged.HasDelegate)
        {
            // Controlled: adopt any incoming Value that isn't the echo of our own change.
            if (!Equals(Value, _lastPushed))
            {
                _activeItemId = Value;
                _lastPushed = Value;
            }
        }
        else if (!Equals(Value, _lastValueParam))   // Uncontrolled: adopt only on a genuine param change
        {
            _activeItemId = Value;
            _lastValueParam = Value;
        }
    }

    // Ordered list of top-level trigger element ids, registered by each
    // NavigationMenuItem so the menu can move focus between them with the arrow
    // keys (roving — APG navigation pattern). Registration follows DOM order
    // because items render top-to-bottom.
    private readonly List<string> _triggerIds = new();

    // When a trigger opens its submenu via the keyboard (ArrowDown), focus must
    // move INTO the content. The trigger can't focus the content synchronously in
    // its keydown handler: SetActiveItemId only schedules the re-render that
    // mounts the content <div>, so the element doesn't exist in the DOM yet and
    // the focus call is silently dropped in a real browser. Instead the trigger
    // records a one-shot request here, and NavigationMenuContent consumes it from
    // its own OnAfterRenderAsync — i.e. AFTER the content has actually rendered.
    private string? _focusContentOnOpenItemId;

    private string CssClass => Cx.Merge("relative z-10 flex max-w-max flex-1 items-center justify-center", Class);

    private async Task SetActiveItemId(string? value)
    {
        _activeItemId = value;
        _lastPushed = value;   // record what we push so a synchronous controlled veto is detectable
        await ValueChanged.InvokeAsync(value);
        StateHasChanged();
    }

    // Called by a trigger when it opens its submenu via the keyboard. The focus
    // request is deferred until the matching content has rendered (consumed in
    // NavigationMenuContent.OnAfterRenderAsync) so focus lands on a live element.
    internal void RequestContentFocusOnOpen(string itemId) => _focusContentOnOpenItemId = itemId;

    // Returns true (and clears the one-shot request) when the just-rendered
    // content belongs to the item whose submenu was opened from the keyboard.
    internal bool TryConsumeContentFocusRequest(string itemId)
    {
        if (_focusContentOnOpenItemId != itemId) return false;
        _focusContentOnOpenItemId = null;
        return true;
    }

    internal void RegisterTrigger(string id)
    {
        if (!_triggerIds.Contains(id)) _triggerIds.Add(id);
    }

    internal void UnregisterTrigger(string id) => _triggerIds.Remove(id);

    // Reconcile open submenu state when an item is torn down. If the removed
    // item is the one whose submenu is currently open, clear _activeItemId so the
    // Viewport/Indicator (which gate purely on ActiveItemId is not null) don't
    // stay stuck open referencing a no-longer-rendered item. Compared against the
    // live field — not the cascaded snapshot — and scoped to the specific removed
    // id so a momentary list churn elsewhere can't disturb an unrelated open item.
    internal void NotifyItemRemoved(string itemId)
    {
        if (_activeItemId == itemId)
        {
            _activeItemId = null;
            StateHasChanged();
        }
    }

    // Move focus to the trigger `delta` positions from `currentId` (wrapping).
    // Used by NavigationMenuTrigger's ArrowLeft/ArrowRight handlers.
    internal async Task FocusTriggerRelative(string currentId, int delta)
    {
        if (_triggerIds.Count == 0) return;
        var index = _triggerIds.IndexOf(currentId);
        if (index < 0) return;
        var next = ((index + delta) % _triggerIds.Count + _triggerIds.Count) % _triggerIds.Count;
        try { await Interop.FocusElement(_triggerIds[next]); } catch (JSDisconnectedException) { }
    }

    internal async Task FocusTriggerEdge(bool last)
    {
        if (_triggerIds.Count == 0) return;
        try { await Interop.FocusElement(last ? _triggerIds[^1] : _triggerIds[0]); }
        catch (JSDisconnectedException) { }
    }

    public record NavigationMenuContext(string? ActiveItemId, EventCallback<string?> SetActiveItemId, NavigationMenu Owner, int CloseDelayMs);
}

@namespace Lumeo
@implements IAsyncDisposable
@implements IOverlayExitCallback

@if (_exit.Present(IsOpen))
{
    <div id="@_contentId" role="menu" aria-labelledby="@ItemContext.TriggerId" data-state="@(IsOpen ? "open" : "closed")" class="@CssClass" @onkeydown="HandleKeyDown" tabindex="-1" inert="@ExitInert" @attributes="AdditionalAttributes">
        <div class="@InnerCssClass">
            @ChildContent
        </div>
    </div>
}

@inject IComponentInteropService Interop

@code {
    [CascadingParameter] public NavigationMenu.NavigationMenuContext Context { get; set; } = default!;
    [CascadingParameter] public NavigationMenuItem.NavigationMenuItemContext ItemContext { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Use the content id from the item context so the trigger's aria-controls
    // points here and ArrowDown on the trigger can focus this element.
    private string _contentId => ItemContext.ContentId;
    private bool _registered;

    // B11 exit latch (shared infra). Enter keeps fade-in; the submenu panel is wide,
    // so exit mirrors it with a symmetric fade-out rather than a zoom.
    private readonly OverlayExitAnimator _exit = new();
    private DotNetObjectReference<NavigationMenuContent>? _selfRef;
    private const int ExitDurationMs = 250;

    private bool IsOpen => Context.ActiveItemId == ItemContext.ItemId;

    // pointer-events-none blocks the pointer on the fading panel; `inert` (rendered
    // only during the exit window) additionally removes its native links/buttons from
    // the tab order + a11y tree so keyboard users can't Tab into a visually-closed
    // submenu while it animates out (round-1 added neither here — P2). Focus already
    // left on close (Escape returns it to the trigger), so inert traps nothing.
    private string AnimationClass => _exit.Exiting ? "animate-fade-out pointer-events-none" : "animate-fade-in";
    private string? ExitInert => _exit.Exiting ? "true" : null;

    private string CssClass => Cx.Merge("fixed z-50", AnimationClass, Class);

    private string InnerCssClass => "mt-1.5 min-w-[12rem] overflow-hidden rounded-md border border-border/40 bg-popover p-4 text-popover-foreground shadow-lg";

    protected override void OnParametersSet()
        => _exit.OnParameters(IsOpen, ExitDurationMs, () => InvokeAsync(FinishExit));

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (Context.ActiveItemId == ItemContext.ItemId && !_registered)
        {
            await Interop.PositionFixed(_contentId, ItemContext.TriggerId, "start");
            await Interop.RegisterClickOutside(_contentId, ItemContext.TriggerId, async () =>
            {
                await Context.SetActiveItemId.InvokeAsync(null);
                await InvokeAsync(StateHasChanged);
            });
            _registered = true;

            // If this submenu was opened from the keyboard (ArrowDown on the
            // trigger), move focus INTO the content now that it has actually
            // rendered. The trigger can't focus it synchronously — the element
            // didn't exist yet when its keydown handler ran (mirrors
            // MenubarContent's focus-into-content on the open transition).
            if (Context.Owner.TryConsumeContentFocusRequest(ItemContext.ItemId))
            {
                try { await Interop.FocusElement(_contentId); } catch (JSDisconnectedException) { }
            }
        }
        else if (Context.ActiveItemId != ItemContext.ItemId && _registered)
        {
            // Cleanup runs immediately on close (stops the reposition rAF, leaves the
            // inline top/left so the box freezes while the fade-out plays).
            await Cleanup();
        }

        await _exit.WireExitAsync(async () =>
        {
            _selfRef ??= DotNetObjectReference.Create(this);
            try { await Interop.AttachOverlayExitEnd(_contentId, _selfRef); }
            catch (JSDisconnectedException) { }
        });
    }

    [JSInvokable]
    public Task OnExitAnimationEnd() => InvokeAsync(FinishExit);

    private void FinishExit()
    {
        if (_exit.Finish()) StateHasChanged();
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Escape")
        {
            await Context.SetActiveItemId.InvokeAsync(null);
            // Return focus to the trigger so the user isn't stranded.
            try { await Interop.FocusElement(ItemContext.TriggerId); } catch (JSDisconnectedException) { }
        }
    }

    private async Task Cleanup()
    {
        try { await Interop.UnpositionFixed(_contentId); } catch (JSDisconnectedException) { }
        try { await Interop.UnregisterClickOutside(_contentId); } catch (JSDisconnectedException) { }
        _registered = false;
    }

    public async ValueTask DisposeAsync()
    {
        _exit.Dispose();
        _selfRef?.Dispose();
        if (_registered) await Cleanup();
    }
}

